const body = $input.first().json.body || {};

if (!body.phone) {
  throw new Error('O número de telefone é obrigatório');
}

// Limpa o número para deixar apenas dígitos
let phone = String(body.phone).replace(/\D/g, '');

// Adiciona 55 se faltar o DDI
if (phone.length === 10 || phone.length === 11) {
  phone = '55' + phone;
}

return [{
  json: {
    phone: phone,
    instanceName: body.instanceName || 'HUVI',
    // IMPORTANTE: Insira a URL e a API Key da sua Evolution API abaixo, caso queira substituir a mock.
    evolutionUrl: process.env.EVOLUTION_API_URL || 'http://seu-evolution-api.com',
    evolutionApiKey: process.env.EVOLUTION_API_KEY || 'sua-global-api-key'
  }
}];

const evoRes = $input.first().json;
let code = null;
let success = false;

// Se houver propriedade pairingCode ou code, conectamos com sucesso
if (evoRes && (evoRes.pairingCode || evoRes.code)) {
  code = evoRes.pairingCode || evoRes.code;
  success = true;
} else if (evoRes && evoRes.status === 404) {
  // Instância não encontrada ou erro
  code = null;
} else {
  // MOCK DE FALLBACK: Se a API não estiver configurada no nó anterior, enviamos um código fictício para testes.
  code = 'HUVI-' + Math.floor(1000 + Math.random() * 9000);
  success = true;
}

return [{
  json: {
    success,
    code,
    raw_response: evoRes
  }
}];
